import React from 'react';
import { View, TextInput, TouchableOpacity, Text, StyleSheet } from 'react-native';

interface Props {
  value: string;
  onChange: (val: string) => void;
  onPlot: () => void;
  error: string | null;
}

export default function EquationInput({ value, onChange, onPlot, error }: Props) {
  return (
    <View style={styles.wrapper}>
      <View style={styles.row}>
        <View style={styles.inputWrap}>
          <Text style={styles.fxLabel}>f(x) =</Text>
          <TextInput
            value={value}
            onChangeText={onChange}
            onSubmitEditing={onPlot}
            placeholder="x^2, sin(x), 2x+1 …"
            placeholderTextColor="rgba(124,58,237,0.35)"
            style={styles.input}
            autoCapitalize="none"
            autoCorrect={false}
            returnKeyType="done"
          />
        </View>
      </View>
      <TouchableOpacity onPress={onPlot} style={styles.plotBtn} activeOpacity={0.8}>
        <Text style={styles.plotBtnText}>Generate Plot</Text>
      </TouchableOpacity>
      {error && <Text style={styles.error}>{error}</Text>}
    </View>
  );
}

const styles = StyleSheet.create({
  wrapper: {
    paddingHorizontal: 14,
    paddingBottom: 10,
    gap: 10,
  },
  row: {
    flexDirection: 'row',
    gap: 8,
  },
  inputWrap: {
    flex: 1,
    flexDirection: 'row',
    alignItems: 'center',
    backgroundColor: '#1a1c3a',
    borderWidth: 1.5,
    borderColor: '#3730a3',
    borderRadius: 10,
    paddingHorizontal: 14,
    paddingVertical: 2,
  },
  fxLabel: {
    color: '#7c3aed',
    fontSize: 13,
    fontFamily: 'monospace',
    fontWeight: '700',
    marginRight: 8,
  },
  input: {
    flex: 1,
    paddingVertical: 11,
    color: '#e2e8f0',
    fontSize: 15,
    fontFamily: 'monospace',
  },
  plotBtn: {
    backgroundColor: '#7c3aed',
    borderRadius: 10,
    paddingVertical: 13,
    alignItems: 'center',
    justifyContent: 'center',
  },
  plotBtnText: {
    color: '#fff',
    fontSize: 15,
    fontWeight: '700',
    letterSpacing: 0.3,
  },
  error: {
    color: '#f87171',
    fontSize: 12,
    paddingLeft: 2,
  },
});