import React from 'react';
import {
  View, Text, StyleSheet, SafeAreaView,
  KeyboardAvoidingView, Platform, ScrollView,
} from 'react-native';
import { useGraph } from '../lib/useGraph';
import PresetBar from './PresetBar';
import EquationInput from './EquationInput';
import EquationTags from './EquationTags';
import GraphCanvas from './GraphCanvas';

export default function MathGraph() {
  const {
    equations, inputValue, setInputValue,
    view, error,
    addEquation, removeEquation, handlePlot,
    zoomIn, zoomOut, resetView,
  } = useGraph();

  return (
    <SafeAreaView style={styles.safe}>
      <KeyboardAvoidingView
        style={styles.flex}
        behavior={Platform.OS === 'ios' ? 'padding' : undefined}
      >
        <ScrollView
          style={styles.flex}
          contentContainerStyle={styles.content}
          keyboardShouldPersistTaps="handled"
          showsVerticalScrollIndicator={false}
        >
          {/* Header */}
          <View style={styles.header}>
            <Text style={styles.headerTitle}>📐 MathGraph</Text>
            <Text style={styles.headerSub}>Visualize equations instantly</Text>
          </View>

          {/* Divider */}
          <View style={styles.divider} />

          {/* Presets */}
          <PresetBar onSelect={expr => { setInputValue(expr); addEquation(expr); }} />

          <View style={styles.divider} />

          {/* Input */}
          <View style={styles.section}>
            <EquationInput
              value={inputValue}
              onChange={setInputValue}
              onPlot={handlePlot}
              error={error}
            />
          </View>

          {/* Tags */}
          {equations.length > 0 && (
            <>
              <View style={styles.divider} />
              <EquationTags equations={equations} onRemove={removeEquation} />
            </>
          )}

          <View style={styles.divider} />

          {/* Graph */}
          <GraphCanvas
            equations={equations}
            view={view}
            onZoomIn={zoomIn}
            onZoomOut={zoomOut}
            onReset={resetView}
          />

          {/* Hint */}
          <Text style={styles.hint}>Touch the graph to inspect values</Text>
        </ScrollView>
      </KeyboardAvoidingView>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  safe: {
    flex: 1,
    backgroundColor: '#0d0f1e',
  },
  flex: {
    flex: 1,
  },
  content: {
    paddingBottom: 30,
  },
  header: {
    paddingHorizontal: 16,
    paddingTop: 16,
    paddingBottom: 14,
    backgroundColor: '#11132a',
    alignItems: 'center',
  },
  headerTitle: {
    fontSize: 20,
    fontWeight: '700',
    color: '#fff',
    letterSpacing: -0.3,
  },
  headerSub: {
    fontSize: 12,
    color: 'rgba(167,139,250,0.5)',
    marginTop: 3,
  },
  divider: {
    height: 1,
    backgroundColor: 'rgba(124,58,237,0.15)',
  },
  section: {
    paddingTop: 12,
  },
  hint: {
    textAlign: 'center',
    fontSize: 11,
    color: 'rgba(124,58,237,0.35)',
    marginTop: 8,
  },
});